class NestedIterator {
  constructor(nestedList) { this.res = []; const dfs = (arr) => { for(let a of arr) { if(a.isInteger()) this.res.push(a.getInteger()); else dfs(a.getList()); } }; dfs(nestedList); this.i = 0; }
  next() { return this.res[this.i++]; }
  hasNext() { return this.i < this.res.length; }
}

